import anthropic
import pandas as pd
import sqlalchemy
from typing import Any

client = anthropic.Anthropic()

# Core ETL tools exposed to the agent
tools = [
    {
        "name": "inspect_schema",
        "description": "Return the column names, types, and nullable flags for a database table.",
        "input_schema": {
            "type": "object",
            "properties": {
                "connection_string": {"type": "string", "description": "SQLAlchemy connection string"},
                "table_name": {"type": "string", "description": "Fully qualified table name, e.g. public.orders"}
            },
            "required": ["connection_string", "table_name"]
        }
    },
    {
        "name": "read_table",
        "description": "Read rows from a database table using a SQL query. Returns up to max_rows rows.",
        "input_schema": {
            "type": "object",
            "properties": {
                "connection_string": {"type": "string"},
                "query": {"type": "string", "description": "SELECT statement to execute"},
                "max_rows": {"type": "integer", "default": 10000}
            },
            "required": ["connection_string", "query"]
        }
    },
    {
        "name": "assert_quality",
        "description": "Run quality checks on a dataset. Checks: row_count_min, null_rate_max per column, value_range.",
        "input_schema": {
            "type": "object",
            "properties": {
                "dataset_ref": {"type": "string", "description": "Key into the state store for a loaded DataFrame"},
                "checks": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "properties": {
                            "type": {"type": "string", "enum": ["row_count_min", "null_rate_max", "value_range"]},
                            "column": {"type": "string"},
                            "value": {}
                        }
                    }
                }
            },
            "required": ["dataset_ref", "checks"]
        }
    },
    {
        "name": "write_table",
        "description": "Write a DataFrame from the state store to a database table.",
        "input_schema": {
            "type": "object",
            "properties": {
                "dataset_ref": {"type": "string"},
                "connection_string": {"type": "string"},
                "table_name": {"type": "string"},
                "if_exists": {"type": "string", "enum": ["replace", "append", "fail"], "default": "append"}
            },
            "required": ["dataset_ref", "connection_string", "table_name"]
        }
    }
]

import json

# State store: holds DataFrames by reference key
state: dict[str, pd.DataFrame] = {}

def handle_tool_call(name: str, inputs: dict) -> Any:
    if name == "inspect_schema":
        engine = sqlalchemy.create_engine(inputs["connection_string"])
        with engine.connect() as conn:
            result = conn.execute(
                sqlalchemy.text(
                    "SELECT column_name, data_type, is_nullable "
                    "FROM information_schema.columns "
                    "WHERE table_schema || '.' || table_name = :table"
                ),
                {"table": inputs["table_name"]}
            )
            columns = [{"name": r[0], "type": r[1], "nullable": r[2] == "YES"} for r in result]
        return {"columns": columns, "row_count_estimate": None}

    elif name == "read_table":
        engine = sqlalchemy.create_engine(inputs["connection_string"])
        df = pd.read_sql_query(
            inputs["query"],
            engine,
            # Avoid loading unbounded results
        ).head(inputs.get("max_rows", 10000))
        ref = f"df_{len(state)}"
        state[ref] = df
        return {
            "dataset_ref": ref,
            "row_count": len(df),
            "columns": list(df.columns),
            "dtypes": df.dtypes.astype(str).to_dict(),
            "sample": df.head(3).to_dict(orient="records")
        }

    elif name == "assert_quality":
        df = state[inputs["dataset_ref"]]
        failures = []
        for check in inputs["checks"]:
            if check["type"] == "row_count_min":
                if len(df) < check["value"]:
                    failures.append(f"Row count {len(df)} below minimum {check['value']}")
            elif check["type"] == "null_rate_max":
                col = check["column"]
                rate = df[col].isna().mean()
                if rate > check["value"]:
                    failures.append(f"Column '{col}' null rate {rate:.2%} exceeds max {check['value']:.2%}")
        return {"passed": len(failures) == 0, "failures": failures}

    elif name == "write_table":
        df = state[inputs["dataset_ref"]]
        engine = sqlalchemy.create_engine(inputs["connection_string"])
        df.to_sql(
            inputs["table_name"].split(".")[-1],
            engine,
            schema=inputs["table_name"].split(".")[0] if "." in inputs["table_name"] else None,
            if_exists=inputs.get("if_exists", "append"),
            index=False
        )
        return {"rows_written": len(df), "table": inputs["table_name"]}

    else:
        raise ValueError(f"Unknown tool: {name}")

import re

def validate_read_query(sql: str) -> None:
    """Reject any query that is not a plain SELECT."""
    normalized = sql.strip().upper()
    # Disallow any statement that modifies data
    dangerous_keywords = [
        r"\bINSERT\b", r"\bUPDATE\b", r"\bDELETE\b",
        r"\bDROP\b", r"\bCREATE\b", r"\bALTER\b",
        r"\bTRUNCATE\b", r"\bGRANT\b", r"\bREVOKE\b",
        r"\bEXEC\b", r"\bEXECUTE\b"
    ]
    for pattern in dangerous_keywords:
        if re.search(pattern, normalized):
            raise ValueError(f"Disallowed SQL keyword detected: {pattern}")
    if not normalized.startswith("SELECT"):
        raise ValueError("Only SELECT statements are permitted in read_table")
